func toSessionDTO(s store.Session) sessionDTO {
	return sessionDTO{
		ID:            s.ID,
		ProjectPath:   s.ProjectPath,
		ProjectName:   s.ProjectName,
		AgentPlugin:   s.AgentPlugin,
		WorkspacePath: s.WorkspacePath,
