  const title = row.title.trim() || `new agent: ${row.id}`;
  const recap = row.recap.trim();

  return {
    agent: row.agentPlugin,
    agentPluginId: row.agentPlugin,
    createdAt: row.createdAt,
    cwd: row.workspacePath,
    description: recap,
    id: row.id,
    issue: '',
    kind: 'worker',
